-- Ken's Hardened V2 Fix

local b64_0x1IlIll = {}
local char_0xl11III='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllllll=1,#char_0xl11III do b64_0x1IlIll[char_0xl11III:sub(i_0xllllll,i_0xllllll)] = i_0xllllll - 1 end

function b64_0x1IlIll.dec_0x1IIlII(d_0xllllII)
    d_0xllllII = string.gsub(d_0xllllII, '[^'..char_0xl11III..'=]', '')
    local r_0xllIIIl = {}
    for i_0xllllll=1, #d_0xllllII, 4 do
        local c_0xl11lIl = b64_0x1IlIll[d_0xllllII:sub(i_0xllllll,i_0xllllll)] or 0
        local c_0xlII1II = b64_0x1IlIll[d_0xllllII:sub(i_0xllllll+1,i_0xllllll+1)] or 0
        local c_0xlIlll1, c_0xlII11I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xllllII:sub(i_0xllllll+2,i_0xllllll+2)
        if ch3 == "=" then has3 = false else c_0xlIlll1 = b64_0x1IlIll[ch3] or 0 end
        local ch4 = d_0xllllII:sub(i_0xllllll+3,i_0xllllll+3)
        if ch4 == "=" then has4 = false else c_0xlII11I = b64_0x1IlIll[ch4] or 0 end
        local b_0xllI1ll = c_0xl11lIl * (2^18) + c_0xlII1II * (2^12) + c_0xlIlll1 * (2^6) + c_0xlII11I
        local b_0x1lI1I1 = math.floor(b_0xllI1ll / (2^16)) % (2^8)
        local b_0xIll1I1 = math.floor(b_0xllI1ll / (2^8)) % (2^8)
        local b_0xI1IIII = b_0xllI1ll % (2^8)
        table.insert(r_0xllIIIl, string.char(b_0x1lI1I1))
        if has3 then table.insert(r_0xllIIIl, string.char(b_0xIll1I1)) end
        if has4 then table.insert(r_0xllIIIl, string.char(b_0xI1IIII)) end
    end
    return table.concat(r_0xllIIIl)
end


local function bxor_0xIIIIl1(a_0xI1IlIl,b_0xlllIII)
    if bit32 then return bit32.bxor(a_0xI1IlIl,b_0xlllIII) end
    local r_0xllll1l = 0
    for i_0xI1IlIl = 0, 7 do
        local x_0x1111ll = a_0xI1IlIl % 2
        local y_0xlIIIIl = b_0xlllIII % 2
        if x_0x1111ll ~= y_0xlIIIIl then r_0xllll1l = r_0xllll1l + (2^i_0xI1IlIl) end
        a_0xI1IlIl = math.floor(a_0xI1IlIl / 2)
        b_0xlllIII = math.floor(b_0xlllIII / 2)
    end
    return r_0xllll1l
end


local function bxor_str_0xIlllll(s_0xI1Il1l, k_0xI1llII)
    local r_0x1III1I = {}
    for i_0xIIIlIl=1, #s_0xI1Il1l do
        local b_0xlllI1l = string.byte(s_0xI1Il1l, i_0xIIIlIl)
        local kb_0xl11lII = string.byte(k_0xI1llII, (i_0xIIIlIl-1) % #k_0xI1llII + 1)
        r_0x1III1I[i_0xIIIlIl] = string.char(bxor_0xIIIIl1(b_0xlllI1l, kb_0xl11lII))
    end
    return table.concat(r_0x1III1I)
end


local function getkeys_0xIllIII()
    local seed = b64_0x1IlIll.dec_0x1IIlII("M3FrdGt3eFU=")
    local k1_enc = b64_0x1IlIll.dec_0x1IIlII("eT9aRwYVCy0=")
    local k2_enc = b64_0x1IlIll.dec_0x1IIlII("ajAPGSodGgI=")
    return bxor_str_0xIlllll(k1_enc, seed), bxor_str_0xIlllll(k2_enc, seed)
end


local function cff_0x1IIl1l(a_0x1IIlII)
    local st_0xllIl1l = 0
    local res_0x1llIl1 = a_0x1IIlII
    while true do
        if st_0xllIl1l == 0 then
            res_0x1llIl1 = res_0x1llIl1 + 1
            st_0xllIl1l = 1
        elseif st_0xllIl1l == 1 then
            res_0x1llIl1 = res_0x1llIl1 * 2
            st_0xllIl1l = 2
        elseif st_0xllIl1l == 2 then
            res_0x1llIl1 = res_0x1llIl1 - 3
            st_0xllIl1l = 3
        else
            break
        end
    end
    return res_0x1llIl1
end


local function chain_0xllI1Il(x) return x*2 end
local function chain_0x1lllll(x) return chain_0xllI1Il(x)+1 end


local d_0xIllIl1 = {
  {op=255, val="", is_enc=true},
}
local pc_0xIIl111 = 1
local stk_0xI1IlIl = {}
stk_0xI1IlIl._jmp = nil


local disp_0xIl1lI1 = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIllIII()

local state_0xII1IIl = 0
while true do
    if state_0xII1IIl == 0 then  -- FETCH
        if pc_0xIIl111 > #d_0xIllIl1 then break end
        local inst = d_0xIllIl1[pc_0xIIl111]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0x1IlIll.dec_0x1IIlII(val)
            d = bxor_str_0xIlllll(d, k2)
            val = bxor_str_0xIlllll(d, k1)
        end
        stk_0xI1IlIl._jmp = nil
        pc_0xIIl111 = pc_0xIIl111 + 1
        cur_op_0xI1I1l1 = opcode
        cur_val_0xIlI11I = val
        state_0xII1IIl = 1

    elseif state_0xII1IIl == 1 then  -- EXECUTE
        local handler = disp_0xIl1lI1[cur_op_0xI1I1l1]
        if handler then
            handler(stk_0xI1IlIl, cur_val_0xIlI11I)
        end
        if stk_0xI1IlIl._jmp then
            pc_0xIIl111 = pc_0xIIl111 + stk_0xI1IlIl._jmp
        end
        state_0xII1IIl = 0
    else
        break
    end
end
